
import "./App.css";

import { useState } from "react";
import { db } from "./db.js";
import { useLiveQuery } from "dexie-react-hooks";
import { WeightVisualizer } from "./weights";
import icon from "./weight-calc-icon.svg";
import ghIcon from "./github-icon.svg";
import linkedInIcon from "./linked-in-icon.svg";
function App() {
  return (
    <div className="App">
      <header>
        <div id="logo-container">
          <img src={icon} alt="icon" id="wc-logo"></img>
        </div>
        <div id="social-links">
          <a
            href="https://github.com/alejandrojortiz"
            target={"_blank"}
            rel={"noreferrer"}
          >
            <img src={ghIcon} alt="github-link"></img>
          </a>
          <a
            href="https://www.linkedin.com/in/alejandrojortiz/"
            target={"_blank"}
            rel={"noreferrer"}
          >
            <img src={linkedInIcon} alt="linked-in-link"></img>
          </a>
        </div>
      </header>
      <WeightInputForm />
    </div>
  );
}
function WeightInputForm() {
  // Array to store the weights from the weight inputs
  const [weightInputs, setWeightInputs] = useState([{weight: '', amount: ''}]);
  // Stores the result of calculating the weight layout
  const [weightLayout, setWeightLayout] = useState("");
  // Stores the desired weight
  const [weightTarget, setWeightTarget] = useState(0);
  // Stores the bar weight
  const [barWeight, setBarWeight] = useState(0);
  const [renderWeights, setRenderWeights] = useState([]);
  // Stores the saved layouts
  const [savedLayouts, setSavedLayouts] = useState(() => {
    let ret = [];
    async function populate() {
      const lays = await db.layouts.toArray();
      if (lays.length !== 0) {
        for (let i = 0; i < lays.length; i++) {
          ret = [...ret, lays[i].name];
        }
      }
    }
    populate().then(() => {
      ret.sort();
      setSavedLayouts(ret);
      setChosenSavedLayout(ret[0]);
    });
    return ret;
  });
  useLiveQuery(() => {
    let ret = [];
    async function populate() {
      const lays = await db.layouts.toArray();
      if (lays.length !== 0) {
        for (let i = 0; i < lays.length; i++) {
          ret = [...ret, lays[i].name];
        }
      }
    }
    populate().then(() => {
      ret.sort();
      setSavedLayouts(ret);
      // setChosenSavedLayout(ret[0]);
    });
    return ret;
  });
  // Stores the selected saved layout to load
  const [chosenSavedLayout, setChosenSavedLayout] = useState("");
  // Comparator to sort the weightInputs (A, B) by weight (B - A for descending order)
  const compWeightInputs = (inputA, inputB) => {
    return Number(inputB.weight) - Number(inputA.weight);
  };
  // Handles changes in the weight inputs
  const handleFormChange = (index, event) => {
    let data = [...weightInputs];
    data[index][event.target.name] = event.target.value;
    setWeightInputs(data);
  };
  // Adds a weight input field
  const addWeightInput = () => {
    let newWeightInput = { weight: "", amount: "" };
    setWeightInputs([...weightInputs, newWeightInput]);
  };
  // Removes the index-th weight input field
  const removeWeightInput = (index) => {
    let data = [...weightInputs];
    data.splice(index, 1);
    setWeightInputs(data);
  };
  // Calculates the weight layout for given weights and target
  // Runs after clicking the "Calculate" button
  const calculateWeights = (e) => {
    e.preventDefault();
    const weights = weightInputs.map((input) => {
      return { weight: input.weight * 100, amount: input.amount };
    });
    weights.sort(compWeightInputs);
    if (weightTarget - barWeight === 0) {
      setWeightLayout("Just the bar");
      setRenderWeights([]);
      return;
    }
    const toRet = weightCalc((weightTarget - barWeight) * 100, weights);
    let toLayout;
    let newRenderWeights = [];
    if (toRet != null) {
      toLayout = "Use ";
      for (const weight of toRet.keys()) {
        toLayout += `${toRet.get(weight)} ${weight / 100}s, `;
        newRenderWeights = [
          ...newRenderWeights,
          { weight: weight, amount: toRet.get(weight) },
        ];
      }
      toLayout = toLayout.slice(0, toLayout.length - 2);
    } else toLayout = "Unable to make desired weight";
    setWeightLayout(toLayout);
    setRenderWeights(newRenderWeights);
  };
  // Implements the calculation of the weights
  const weightCalc = (target, weights) => {
    const combos = new Map();
    let sum = 0;
    for (let i = 0; i < weights.length; i++) {
      let diff = target - sum;
      let numWeights = Math.floor(diff / weights[i]["weight"] / 2) * 2; // Only even amounts in this pass
      if (numWeights === 0) continue;
      let added = Math.min(
        numWeights,
        Math.floor(weights[i]["amount"] / 2) * 2
      ); // don't add more weights than remain, and only add even amounts of those
      sum += added * weights[i]["weight"];
      combos.set(weights[i].weight, added);
      weights[i].amount -= added;
      if (sum === target) return combos;
    }
    return null;
  };
  const saveCurrentLayout = () => {
    let name;
    let id;
    async function saveLayout() {
      name = prompt("Enter exercise name:").toLowerCase();
      if (!name) throw new Error("No name entered");
      id = await db.layouts.add({
        name,
        weightInputs,
        weightTarget,
        barWeight,
        weightLayout,
        renderWeights,
      });
    }
    saveLayout()
      .then(() => {
        if (name) {
          addSavedLayout(name);
          console.log(`Successfully stored ${name} with id: ${id}`);
        }
      })
      .catch((error) => {
        async function modifyLayout() {
          await db.layouts.where("name").equalsIgnoreCase(name).modify({
            weightInputs: weightInputs,
            weightTarget: weightTarget,
            barWeight: barWeight,
            weightLayout: weightLayout,
            renderWeights: renderWeights,
          });
        }
        if (error.name === "ConstraintError") {
          // modify existing layout
          modifyLayout()
            .then(console.log(`Modified ${name}`))
            .catch((error) =>
              console.log(`Failed to modify ${name} with error: ${error}`)
            );
        } else console.log(`Failed to add ${name} with error: ${error}`);
      });
  };
  // Handles adding a new saved layout option
  const addSavedLayout = (name) => {
    let newVersion = [...savedLayouts, String(name)].sort();
    setSavedLayouts(newVersion);
    setChosenSavedLayout(name);
  };
  // Loads the selected layout
  const loadSavedLayout = () => {
    async function load() {
      const exercise = chosenSavedLayout;
      const lay = await db.layouts.where("name").equals(exercise).toArray(); // Have to convert to array or else it won't work
      setWeightInputs(lay[0].weightInputs);
      setWeightTarget(lay[0].weightTarget);
      setBarWeight(lay[0].barWeight);
      setWeightLayout(lay[0].weightLayout);
      setRenderWeights(lay[0].renderWeights);
    }
    load().catch((error) => {
      console.log(`Unable to load: ${error}`);
    });
  };
  // Deletes the selected saved layout
  const deleteSavedLayout = () => {
    async function deleteLayout() {
      const exercise = chosenSavedLayout;
      await db.layouts.where("name").equals(exercise).delete();
    }
    deleteLayout()
      .then(setChosenSavedLayout(savedLayouts[0]))
      .catch((error) => {
        console.log(`Failed to delete: ${error}`);
      });
  };
  return (
    <div className="weight-calculator">
      <div className="button-bar">
        <button
          type="button"
          id="save-layout"
          onClick={() => saveCurrentLayout(weightInputs)}
        >
          Save Layout
        </button>
        <div id="layout-select">
          <select
            id="select-layout"
            value={chosenSavedLayout}
            onChange={(event) => {
              setChosenSavedLayout(event.target.value);
            }}
          >
            {savedLayouts.map((savedLayout, index) => {
              return <option key={index}>{savedLayout}</option>;
            })}
          </select>
          <button type="button" id="load-layout" onClick={loadSavedLayout}>
            Load Layout
          </button>
        </div>
        <button type="button" id="delete-layout" onClick={deleteSavedLayout}>
          Delete Layout
        </button>
      </div>

      {
        /* Only show paragraph if there's something to show*/
        weightLayout && <p id="calculated-layout-text">{weightLayout}</p>
      }
      <WeightVisualizer
        weightInputs={renderWeights}
        blackWeights={false} /*Add black weight checkbox later*/
        id="weight-visualizer"
      />
      <form className="weight-input-form">
        <div id="target-and-bar">
          <label htmlFor="target-weight-input">
            {"Target Weight: "}
            <input
              type="number"
              value={weightTarget}
              id="target-weight-input"
              onChange={(event) => {
                setWeightTarget(event.target.value);
              }}
            ></input>
          </label>
          <label htmlFor="bar-weight">
            {"Bar Weight: "}
            <input
              type="number"
              id="bar-weight"
              value={barWeight}
              onChange={(event) => {
                setBarWeight(event.target.value);
              }}
            />
          </label>
        </div>
        <div className="weight-input-fields">
          {weightInputs.map((input, index) => {
            return (
              <div key={index}>
                <hr />
                <div className="weight-input">
                  <label htmlFor={`weight-input${index}`}>
                    {"Weight: "}
                    <input
                      type="number"
                      id={`weight-input${index}`}
                      name="weight"
                      value={input.weight}
                      onChange={(event) => handleFormChange(index, event)}
                    />
                  </label>
                  <label htmlFor={`weight-amount${index}`}>
                    {"Amount: "}
                    <input
                      type="number"
                      name="amount"
                      id={`weight-amount${index}`}
                      value={input.amount}
                      onChange={(event) => handleFormChange(index, event)}
                    />
                  </label>
                  <button
                    type="button"
                    onClick={() => removeWeightInput(index)}
                  >
                    Remove
                  </button>
                </div>
              </div>
            );
          })}
        </div>
        <button type="button" id="add-weight" onClick={addWeightInput}>
          Add weight
        </button>
        <button type="button" id="calculate-button" onClick={calculateWeights}>
          Calculate
        </button>
      </form>
      <button
        type="button"
        id="delete-all-layouts"
        onClick={() => {
          async function clearAll() {
            await db.delete();
            db.open(2);
            console.log("Cleared database");
            setSavedLayouts([]); // clear select options bc they're no longer saved
          }
          clearAll().then(console.log("Deleted all layouts"));
        }}
      >
        Delete All Layouts
      </button>
    </div>
  );
}

export default App;
